// Reveal-on-scroll (vanilla, ~200B)
(function(){
  if(!('IntersectionObserver' in window)){document.querySelectorAll('.reveal').forEach(e=>e.classList.add('in'));return}
  var io=new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}})},{threshold:.12,rootMargin:'0px 0px -60px 0px'});
  document.querySelectorAll('.reveal').forEach(function(e){io.observe(e)});
})();
// Lazy-load heavy images (e.g. motion GIF) on viewport entry
(function(){
  var imgs=document.querySelectorAll('img[data-lazy-src]');
  if(!imgs.length)return;
  if(!('IntersectionObserver' in window)){imgs.forEach(function(i){i.src=i.dataset.lazySrc});return}
  var io=new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting){e.target.src=e.target.dataset.lazySrc;io.unobserve(e.target)}})},{rootMargin:'200px 0px'});
  imgs.forEach(function(i){io.observe(i)});
})();

/* Mobile pillar focal: card whose center is closest to viewport center
   gets .is-focal; the others get .is-blur. Active only while pillars are
   stacked single-column (max-width:1100px). */
(function(){
  var cards=document.querySelectorAll('.pillars-section .show-card');
  if(!cards.length) return;
  var mq=window.matchMedia('(max-width:1100px)');
  var raf=null;

  function update(){
    raf=null;
    if(!mq.matches){
      cards.forEach(function(c){c.classList.remove('is-focal','is-blur')});
      return;
    }
    var vh=window.innerHeight;
    var center=vh/2;
    var nearest=null,best=1e9;
    cards.forEach(function(c){
      var r=c.getBoundingClientRect();
      // Card must be reasonably visible
      if(r.bottom<60 || r.top>vh-60){return}
      var cc=r.top+r.height/2;
      var d=Math.abs(cc-center);
      if(d<best){best=d;nearest=c}
    });
    cards.forEach(function(c){
      if(c===nearest){c.classList.add('is-focal');c.classList.remove('is-blur')}
      else if(nearest){c.classList.remove('is-focal');c.classList.add('is-blur')}
      else{c.classList.remove('is-focal','is-blur')}
    });
  }
  function onScroll(){if(!raf) raf=requestAnimationFrame(update)}
  window.addEventListener('scroll',onScroll,{passive:true});
  window.addEventListener('resize',onScroll);
  mq.addEventListener && mq.addEventListener('change',onScroll);
  update();
})();

